/**
 * Vocabulary graph — typed loader for generated JSON data.
 *
 * @remarks
 * Generated by the vocabulary graph JSON writer.
 * Imports raw JSON data and re-exports it with TypeScript interfaces.
 */
import { createRequire } from 'node:module';
import type { VocabularyGraph } from './types.js';

const require = createRequire(import.meta.url);
// Direct type annotation is acceptable here: VocabularyGraph contains only
// primitive fields (string, number, boolean, Record<string, number>) with no
// union literals requiring runtime validation. Unlike PrerequisiteGraph (which
// validates 'prerequisiteFor' | 'thread' | 'priorKnowledge' at load time),
// this shape cannot contain type-narrowing surprises from JSON.
const data: VocabularyGraph = require('./data.json');

/**
 * Vocabulary graph with curriculum terms and definitions.
 *
 * @remarks
 * Contains curriculum vocabulary with definitions, frequency counts,
 * and cross-subject identification.
 * Use for glossary lookups and vocabulary progression queries.
 */
export const vocabularyGraph: VocabularyGraph = data;

export type { VocabularyGraph, VocabularyGraphStats, VocabularyNode } from './types.js';
